import React, { useState, useEffect } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [selectedPdf, setSelectedPdf] = useState(null);
  const [pdfs, setPdfs] = useState([]);
  const [watsonResponses, setWatsonResponses] = useState({
    summary: { content: "", model: "" },
    recommendations: { content: "", model: "" },
    insights: { content: "", model: "" },
    key_actions: { content: "", model: "" },
  });
  const [loading, setLoading] = useState({
    summary: false,
    recommendations: false,
    insights: false,
    key_actions: false,
  });
  const [chatContext, setChatContext] = useState({
    documentContext: "",
    userInput: "",
    conversationHistory: [],
  });

  // Fetch PDFs and analyze when selected
  useEffect(() => {
    const fetchPdfs = async () => {
      try {
        const response = await axios.get("http://localhost:8000/pdfs");
        setPdfs(response.data);
      } catch (error) {
        console.error("Error fetching PDFs:", error);
      }
    };
    fetchPdfs();
  }, []);

  // Analyze specific section
  const analyzeSectionFromPdf = async (section) => {
    if (!selectedPdf) return;

    setLoading((prev) => ({ ...prev, [section]: true }));

    try {
      const response = await axios.post(
        "http://localhost:8000/analyze-section",
        {
          pdf: selectedPdf,
          section: section,
          max_tokens: 300,
          temperature: 0.7,
        }
      );

      // Update section response and build document context
      setWatsonResponses((prev) => ({
        ...prev,
        [section]: {
          content: response.data.content,
          model: response.data.model,
        },
      }));

      // Accumulate document context for chat
      setChatContext((prev) => ({
        ...prev,
        documentContext:
          prev.documentContext +
          `\n\n${section.toUpperCase()}:\n${response.data.content}`,
      }));
    } catch (error) {
      console.error(`Error analyzing ${section}:`, error);
    } finally {
      setLoading((prev) => ({ ...prev, [section]: false }));
    }
  };

  // Analyze all sections when PDF is selected
  useEffect(() => {
    if (selectedPdf) {
      const sections = [
        "summary",
        "recommendations",
        "insights",
        "key_actions",
      ];
      sections.forEach(analyzeSectionFromPdf);
    }
  }, [selectedPdf]);

  // Chat with document functionality
  const handleChatSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await axios.post(
        "http://localhost:8000/chat-with-document",
        {
          user_input: chatContext.userInput,
          document_context: chatContext.documentContext,
        }
      );

      setChatContext((prev) => ({
        ...prev,
        conversationHistory: [
          ...prev.conversationHistory,
          { type: "user", message: prev.userInput },
          { type: "assistant", message: response.data.response },
        ],
        userInput: "",
      }));
    } catch (error) {
      console.error("Chat error:", error);
    }
  };

  return (
    <div className="app-container">
      <div className="left-panel">
        {/* Watson Analysis Sections */}
        <div className="watson-sections">
          {Object.entries(watsonResponses).map(([key, value]) => (
            <div key={key} className="watson-section">
              <h3>
                {key
                  .replace("_", " ")
                  .split(" ")
                  .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
                  .join(" ")}
              </h3>

              {loading[key] ? (
                <p>Loading {key.replace("_", " ")}...</p>
              ) : (
                <p>
                  {value.content || `No ${key.replace("_", " ")} available`}
                </p>
              )}
            </div>
          ))}
        </div>

        {/* Chat with Document Section */}
        <div className="chat-section">
          <div className="chat-history">
            {chatContext.conversationHistory.map((msg, index) => (
              <div key={index} className={`chat-message ${msg.type}`}>
                {msg.message}
              </div>
            ))}
          </div>
          <form onSubmit={handleChatSubmit} className="chat-input">
            <input
              type="text"
              value={chatContext.userInput}
              onChange={(e) =>
                setChatContext((prev) => ({
                  ...prev,
                  userInput: e.target.value,
                }))
              }
              placeholder="Chat with your document..."
            />
            <button type="submit">Send</button>
          </form>
        </div>
      </div>

      {/* PDF Selection Panel */}
      <div className="right-panel">
        <select
          onChange={(e) => setSelectedPdf(e.target.value)}
          value={selectedPdf || ""}
        >
          <option value="">Select a PDF</option>
          {pdfs.map((pdf, index) => (
            <option key={index} value={pdf}>
              {pdf}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
}

export default App;
